import{_ as t,o as n,c as i,ag as r}from"./chunks/framework.DXGyWiRo.js";const a="/images/lekt1809.jpg",s="/images/lekt1901.jpg",o="/images/lekt1902.jpg",h="/images/lekt1904.jpg",l="/images/lekt1903.jpg",v=JSON.parse('{"title":"Lektion 19","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion19.md","filePath":"lektionen/lektion19.md"}'),p={name:"lektionen/lektion19.md"};function d(u,e,m,b,c,k){return n(),i("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-19" tabindex="-1">Lektion 19 <a class="header-anchor" href="#lektion-19" aria-label="Permalink to &quot;Lektion 19&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>19.1. Der Relativsatz</li><li>19.2. Das Relativpronomen = व्यपेक्षकसर्वनाम n.</li><li>19.3. Wortliste</li><li>19.4. Übung</li><li>५. सुभाषितानि</li></ul><h2 id="_19-1-der-relativsatz" tabindex="-1">19.1. Der Relativsatz <a class="header-anchor" href="#_19-1-der-relativsatz" aria-label="Permalink to &quot;19.1. Der Relativsatz&quot;">​</a></h2><p>Schema:</p><p>Relativpronomen -- Relativsatz, der das Nomen enthält, auf den sich der Relativsatz bezieht -- (Demonstrativpronomen) -- Hauptsatz</p><p>Der Relativsatz kann auch nach dem Hauptsatz stehen, er kann aber nicht in den hauptsatz eingeschoben werden.</p><p>Das Relativpronomen und das Beziehungswort, das ja - im Gegensatz zum deutschen - im Relativsatz steht, stehen in dem Kasus, den der Relativsatz syntaktisch erfordert. Das Demonstrativpronomen steht in dem Kasus, den der Hauptsatz syntaktisch erfordert.</p><p>Beispiele:</p><p>Anmerkung: In Relativen allgemeingültigen Inhalts wird gerne der Optativ anstelle des Indikativs verwendet. Viele unserer Beispiele würden also bevorzugt im Optativ stehen.</p><p>1. Der Agens (कर्तृ) des Satzes wird durch einen Relativsatz näher bestimmt:</p><blockquote><p>यो नरः पुण्यं करोति स स्वर्गं गच्छति =  यो नरः पुन्यं करोति तेन स्वर्गं गम्यते = येन नरेण पुण्यम् क्रियते तेन स्वर्गं गम्यते u.s.w. = &quot;Ein Mann, der Verdienstvolles tut, kommt in den Himmel.&quot;</p></blockquote><p>2. Das direkte Objekt (कर्म) des Hauptsatzes wird durch den Relativsatz näher bestimmt:</p><blockquote><p>यो ब्राह्मणो देवान्यजते तं देवा रक्षन्ति = &quot;Die Götter beschützen einen Brahmanen, der ihnen als Opferherr opfert.&quot;</p></blockquote><p>3. Die nähere Bestimmung eines Nomens des Hauptsatzes steht im Relativsatz:</p><blockquote><p>ये नराः पापं कुर्वन्ति तेषां पुत्रा धनं न लभन्ते = &quot;Söhne von Männern, die Böses tun, erhalten keinen Reichtum.&quot;</p></blockquote><p>4. Relativpronomen und Beziehungswort stehen im Genetiv (षष्ठी):</p><blockquote><p>यस्य नरस्य पुत्राः पापं कुर्वन्ति स न सुखवान् = &quot;Nicht ist der Mann glücklich, dessen Söhne Böses tun.&quot;</p></blockquote><p>5. Relativpronomen und Beziehungswort stehen im Instrimentalis (तृतीया):</p><blockquote><p>येन शत्रुणा ग्रामो जितस्तं स्विषन्ति = &quot;Sie hassen den Feind, der ihr Dorf besiegt / erobert hat.&quot;</p></blockquote><p>6. Relativpronomen und Beziehungswort stehen im Akkusativ (द्वितीया):</p><blockquote><p>यं नरं देवी रक्षति स सुखमाप्नोति = &quot;Ein Mann, den die Göttin beschützt, erlangt Glück.&quot;</p></blockquote><h2 id="_19-2-das-relativpronomen-व्यपेक्षकसर्वनाम-n" tabindex="-1">19.2. Das Relativpronomen = व्यपेक्षकसर्वनाम n. <a class="header-anchor" href="#_19-2-das-relativpronomen-व्यपेक्षकसर्वनाम-n" aria-label="Permalink to &quot;19.2. Das Relativpronomen = व्यपेक्षकसर्वनाम n.&quot;">​</a></h2><table><tbody><tr><td colspan="5">**यद् &quot;welcher, welche, welches&quot; dekliniert wie तद्, aber mit regelmäßigem Sandhi.**</td></tr><tr><th></th><th></th><th>Maskulinum<br>पुंस्</th><th>Neutrum<br>नपुंसक</th><th>Femininum<br>स्त्री</th></tr><tr><td>**Singular<br>एकवचन**</td><td>**1. Nominativ<br>प्रथमा**</td><th>यस्</th><th>यद्</th><th>या</th></tr><tr><td></td><td>**2. Akkusativ<br>द्विती्या**</td><th>यम्</th><th>यद्</th><th>याम्</th></tr><tr><td></td><td>**3. Instrumentalis<br>तृतीया**</td><th>येन</th><th>येन</th><th>यया</th></tr><tr><td></td><td>**6. Genetiv<br>षष्ठी**</td><th>यस्य</th><th>यस्य</th><th>यस्यास्</th></tr><tr><td>**Plural<br>बहुवचन**</td><td>**1. Nominativ<br>प्रथमा**</td><th>ये</th><th>यानि</th><th>यास्</th></tr><tr><td></td><td>**2. Akkusativ<br>द्वितीया**</td><th>यान्</th><th>यानि</th><th>यास्</th></tr><tr><td></td><td>**3. Instrumentalis<br>तृतीया**</td><th>यैस्</th><th>यैस्</th><th>याभिस्</th></tr><tr><td></td><td>**6. Genetiv<br>षष्ठी**</td><th>येषाम्</th><th>येषाम्</th><th>यासाम्</th></tr><tr><td colspan="5">**Als Vorderglied von Kompisita erscheint der Stamm यद् (unter Beachtung des Sandhi).**</td></tr></tbody></table><h2 id="_19-3-wortliste" tabindex="-1">19.3. Wortliste <a class="header-anchor" href="#_19-3-wortliste" aria-label="Permalink to &quot;19.3. Wortliste&quot;">​</a></h2><p>अर्थ m.: Zweck, Ziel, Bedeutung (eines Wortes), Reichtum, Besitz, Vermögen. अर्थम् (Akk.), अर्थेन (Instr.) mit Gen. oder als Hinterglied eines Tatpuruṣa: um ... willen, um zu.</p><p>अर्थ ist einer der drei Lebenszwecke (पुरुषार्थ), wie sie in der weltlichen und religiösen Literatur beschrieben werden:</p><blockquote><p>धर्म m.: Erlangung von Verdienst durch das Tun, was für einen Recht ist, bzw. zumindest Vermeiden von Übel, welches aus der Nichtbefolgung des Dharma folgen würde</p><p>अर्थ m.: zweckrationales Verhalten, Erlangung von Wohlstand</p><p>काम m.: Sinnenlust, insbes. auch auf sexuellem Gebiet</p></blockquote><p><img src="'+a+'" alt=""><br> Abb.: कामः<br> Illustration zum कामसूत्र<br> [Bildquelle: Wikipedia, Public domain]</p><p>स्था 1 P तिष्ठति Pass. स्थीयते PPP. स्थित : stehen, bleiben, bestehen bleiben, sich befinden. (Wird traditionell zur 1. Präsensklasse gerechnet, obwohl es sich um eine reduplizierende thematische Präsensklasse handelt, wie पा 1 पिबति)</p><p>स्था + उप 1 U उपतिष्ठति : hintreten, sich in ehrerbietiger Haltung vor jemandem hinstellen</p><p>स्था + प्र 1 Ā प्रतिष्ठते : aufbrechen, davongehen</p><p>von स्था :</p><blockquote><p>स्थान n.: Stelle, (rechter) Ort, Standort</p><p>स्थिति f.: Verweilen, Standhaftigkeit, Beharren</p></blockquote><p>गर्भ m.: Gebärmutter, Schoß, Inneres, Embryo / Foetus. Am Ende eines Bahuvrīhi oft: &quot;Inneres&quot;, z.B.</p><blockquote><p>धनगर्भ 3: &quot;dessen Inneres Geld ist = in dem sich Geld befindet&quot;</p><p>गर्भगृह n.: der innerste Schreinraum eines Hindutempels, der das wichtigste Götterbildnis des Tempels enthält (zum Aufbau von Hindutempeln siehe: Volwahsen, A.: Indien : Bauten der Hindus, Buddhisten und Jainas. -- München, 1968)</p><p><img src="'+s+'" alt=""><br> Abb.: गर्भगृहम्, Badami (ಬದಾಮಿ)<br> [Bildquelle: Sudarshan Bhat Khandige / Wikipedia, Public domain]</p></blockquote><p>वारिद m.: Wassergeber = Regenwolke</p><p><img src="'+o+'" alt=""><br> Abb.: वारिदः, Goa (गोंय)<br> [Bildquelle: pichenettes. -- <a href="http://www.flickr.com/photos/_pichenettes_/1257016116/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/_pichenettes_/1257016116/</a>. -- Zugriff am 2008-12-08. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>वा 2 P वाति Pass. वायते PPP. वान / वात : wehen</p><p>davon:</p><blockquote><p>वात m.: Wind</p></blockquote><p>वह् 1 U वहति Pass. उह्यते PPP ऊढ : führen, fahren (trans.)</p><p>छत्त्र् n.: Sonnenschirm, Schirm</p><p><img src="'+h+'" alt=""><br> Abb.: छत्त्रम्</p><blockquote><p>&quot;<em>Onappottan</em> (ഓണപ്പൊട്ടന്‍), in traditional costume is a custom in sourthern parts of Kerala. <em>Onappottan</em> visists houses during the <em>onam</em> and gives blessings. Off late <em>onappottan</em> has become a rare sight, confined to villages.&quot;</p><p>[Bildquelle: Captain Nidish. -- <a href="http://www.flickr.com/photos/captain_nidish/280389572/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/captain_nidish/280389572/</a>. -- Zugriff am 2008-12-08. -- <a href="http://creativecommons.org/licenses/by/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung)]</p></blockquote><p>पण्डित m.: Gelehrter, Weiser ; 3: klug, bewandert (in)</p><p><img src="'+l+'" alt=""><br> Abb.:  पण्डीतः जवाहरलाल नेहरू, १९५९<br> [Bildquelle: Wikipedia, Public domain]</p><p>सेव् 1 Ā सेवते Pass. सेव्यते PPP सेवित : wohnen bei, bewohnen (Akk., Lok.) ; besuchen, sich begeben zu (Akk.) ; bedienen, pflegen, verehren ; üben, gebrauchen ; beiwohnen, Geschlechtsverkehr haben</p><p>नि Präverb: nieder, hinein</p><p>सेव् + नि  1 Ā निषेवते : wohnen bei, bewohnen, besuchen</p><p>अमुत्र : dort, im Jenseits</p><p>इह : hier, im Diesseits</p><p>विद् 6 U विन्दति Pass. विद्यते PPP विन्न / वित्त : finden</p><p>भार्या f.: zu Erhaltende = Gattin</p><p>प्रिय 3: lieb, angenehm</p><p>मित्र n. (!): Freund</p><p>बान्धव m.: Verwandter</p><p>हि : denn, ja nämlich (darf nie am Satzanfang stehen)</p><h2 id="_19-4-ubung" tabindex="-1">19.4. Übung <a class="header-anchor" href="#_19-4-ubung" aria-label="Permalink to &quot;19.4. Übung&quot;">​</a></h2><p>Übersetzen Sie ins Sanskrit:</p><p>1. Die Vaiśyafrau, deren Sohn gestorben ist, weint.</p><p>2. Rāma opfert der Gottheit, die ihn behütet.</p><p>3. Der Dichter preist den Kṣatriya, dessen Reichtum er begehrt.</p><p>4. Feuer verbrennt das Haus des Mannes, der Agni nicht mit einem Opfer verehrt.</p><p>5. Der tigergleiche Mann erschlägt die Kṣatriya-Krieger, die Rāma besieget haben (Passiv).</p><h2 id="५-सुभाषितानि" tabindex="-1">५. सुभाषितानि <a class="header-anchor" href="#५-सुभाषितानि" aria-label="Permalink to &quot;५. सुभाषितानि&quot;">​</a></h2><p>Übersetzen Sie:</p><p>येन येन च वातेन<br> वारिदो वारि मुञ्चति ।<br> तेन तेन च वातेन<br> छत्रं वहति पण्डितः ॥१॥</p><p>Erklärung: वारि Nom., Akk. sg. zu वारि n.: Wasser</p><p>यो धर्ममर्थं कामं च<br> यथाकालं निषेवते ।<br> धर्मार्थकामसंयोगं<br> सो ऽमुत्रेह च विन्दति ॥२॥</p><p>Erklärung: यथाकालम्  Avyayībhavakompositum: zur rechten Zeit ; immer, wenn dafür der rechte Zeitpunkt vorliegt.</p><p>सा भार्या या प्रियं ब्रूते<br> स पुत्रो यस्तु जीवति ।<br> स जीवति गुणो यस्य<br> धर्मो यस्य स जीवति ॥३॥</p><p>यस्यार्थास्तस्य मित्राणि<br> यस्यार्थास्तस्य बान्धवाः ।<br> यस्यार्थाः स पुमांल्लोके<br> यस्यार्थाः स हि पण्डितः ॥४॥</p><p>Erklärung: पुमान् Nom. sg. zu पुंस् &quot;Mann&quot; ; लोके Lokativ sg. zu लोक m.: in der ...</p>',75)])])}const f=t(p,[["render",d]]);export{v as __pageData,f as default};
